VALUES
  ('social-worker-moex-06930', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '女性平均教育程度較高的國家，離婚率較高。由此可以推論：', '["教育程度較高的女性，離婚率較高", "一國的女性平均教育程度與其離婚率正相關", "女性的教育程度與她的離婚機率正相關", "教育程度較高的女性，較能經濟獨立，因此較有能力選擇離婚"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06931', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某大學抽樣調查畢業生流向，首先按各學院的人數比例，分配樣本數；接著各學院內再按性別比例，決 定男女學生的樣本數，然後以學號為抽樣架構，將總人數除以所需樣本數，算出抽樣間距（interval），', '["配額抽樣", "分層抽樣", "等比例抽樣", "系統抽樣 ⑤立意抽樣"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06932', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '青少年安置機構以個案紀錄分析青少年離院原因，由兩位資深社工分別進行編碼，再核對兩人編碼的一 致性。這樣的目的是為了檢驗：', '["內容效度（content validity）", "分數信度（score reliability）", "鑑別度（discriminatory power）", "同時效度（concurrent validity）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06933', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某人想研究父母積極履行親職的行為，正著手列出諸如稱讚、鼓勵、以身作則…等觀察清單。請問他所 進行的這項程序是：', '["概念化", "操作化", "測量化", "標準化"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06934', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '透過加總平均壽命、教育水準、收入三項積分來表示男性和女性的地位，這是那種測量編製方法？', '["評鑑（evaluation）", "評量（assessment）", "量表（scale）", "指數（index）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06935', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列對「線上調查（online survey）」敘述組合，何者正確？①窮人及老人的代表性低  ②無法使用資料', '["具有自動輸入資料的功能", "敏感問題的回答具有匿名效果  ⑤它的完訪率低於面訪", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 13, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06936', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某機構的偏鄉兒童閱讀促進方案，採參加者自願報名方式。方案執行前，參與兒童先接受閱讀能力測驗， 得到的平均數為65分，標準差9分。半年後方案結束，參與兒童接受同樣的閱讀能力測驗，得到的平 均數為76分，標準差20分。推論檢定結果顯示，在沒有變異同質性的假設下，前、後測平均分數有顯', '["此方案能提升兒童閱讀 能力", "此方案對有些兒童效果比較好，有些比較差", "經過此方案後，參與兒童的閱讀能力差異變大", "前、後測的成績因為標準差不同，無法比較"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06937', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '承上題，此方案評估設計，屬於：', '["前實驗（或稱非實驗）設計（pre-experimental design）", "準實驗設計（quasi-experimental design）", "半實驗設計（half-experimental design）", "實驗設計（experimental design）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06938', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '承第14題，此方案評估設計，可能會有那些效度的問題？①成熟因素（maturation）  ②測驗（testing）', '["選擇性偏誤（selection bias）", "迴歸因素（regression）", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06939', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列對「參與式行動研究（participatory action research）」敘述，何者正確﹖', '["它是種基於菁英主義模型下的研究傳統", "它反對把研究主體化約成客體，認為研究者與被研究者之間的區隔應該要消除", "它認為研究的功能主要在生產有效的科學知識", "它倡議掌握資訊與權力的研究者要更有意識的引導研究進行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
